import os, base64, re

BASE = r"E:\Qr_Attendence"

# STEP 1: Reset Scanner.html STUDENTS to empty {}
scanner_path = os.path.join(BASE, "Scanner.html")
with open(scanner_path, "r", encoding="utf-8") as fh:
    html = fh.read()

if re.search(r"const STUDENTS\s*=\s*\{[^;]*\};", html, re.DOTALL):
    new_html = re.sub(
        r"const STUDENTS\s*=\s*\{[^;]*\};",
        "const STUDENTS = {};",
        html, count=1, flags=re.DOTALL)
    with open(scanner_path, "w", encoding="utf-8") as fh:
        fh.write(new_html)
    print(f"Scanner.html rebuilt: {os.path.getsize(scanner_path)/1024:.1f} KB")
else:
    print("WARNING: STUDENTS pattern not found in Scanner.html - file unchanged")

# STEP 2: Rewrite generate_qr.py (content embedded as base64)
_GQR_B64 = ""
gqr_content = base64.b64decode(_GQR_B64)
dest = os.path.join(BASE, "generate_qr.py")
with open(dest, "wb") as fh:
    fh.write(gqr_content)
print(f"generate_qr.py updated: {os.path.getsize(dest)} bytes")
print("All done.")
